 slides.push(slide(11,'Loại khách hàng & nhóm điều trị',`<main><div class="grid2"><section class="panel"><h3>Loại khách hàng</h3>${bars(d.dimensions.customerType,{limit:7,color:'teal'})}</section><section class="panel"><h3>Nhóm điều trị</h3>${rows(d.dimensions.therapy,{limit:8})}</section></div><div class="insight"><b>Dẫn dắt cơ cấu:</b> ${esc(d.dimensions.customerType[0]?.label||'Chưa phân loại')} đạt ${short(d.dimensions.customerType[0]?.revenue||0)}; nhóm điều trị ${esc(d.dimensions.therapy[0]?.label||'Chưa phân nhóm')} đạt ${short(d.dimensions.therapy[0]?.revenue||0)}. Thiếu mapping hiển thị đúng “Chưa phân nhóm”.</div></main>`));
