 const totalSlides=slides.length;const body=slides.map(s=>s.includes('class="slide cover"')?s:s.replace(/<\/section>$/,`${logo(logoSrc)}</section>`)).join('').replaceAll('__TOTAL_SLIDES__',String(totalSlides)).replaceAll('__GENERATED_AT__',esc(generatedAt));
 const js=`(()=>{const s=[...document.querySelectorAll('.slide')];let i=0;function go(n){i=(n+s.length)%s.length;s.forEach((x,j)=>x.classList.toggle('active',j===i));document.getElementById('counter').textContent=(i+1)+' / '+s.length}window.go=go;document.addEventListener('keydown',e=>{if(e.key==='ArrowRight'||e.key==='PageDown')go(i+1);if(e.key==='ArrowLeft'||e.key==='PageUp')go(i-1)});window.__deckQa=()=>{const issues=[];for(const [idx,slide] of s.entries()){slide.classList.add('active');const sr=slide.getBoundingClientRect();for(const el of slide.querySelectorAll('header,main,footer,.logoPlate,.panel,.kpi,.cards article,table,.insight,.warning,.barrow,.product18 span,.riskGrid article,.conclusion article')){if(el.closest('details:not([open])'))continue;const r=el.getBoundingClientRect(),style=getComputedStyle(el);if(style.display==='none'||style.visibility==='hidden')continue;if(r.left<sr.left-1||r.right>sr.right+1||r.top<sr.top-1||r.bottom>sr.bottom+1)issues.push({slide:idx+1,type:'geometry',tag:el.tagName,cls:el.className,left:r.left-sr.left,right:r.right-sr.right,top:r.top-sr.top,bottom:r.bottom-sr.bottom});if(!el.classList.contains('panel')&&(el.scrollWidth>el.clientWidth+2||el.scrollHeight>el.clientHeight+2))issues.push({slide:idx+1,type:'overflow',tag:el.tagName,cls:el.className,scroll:[el.scrollWidth,el.scrollHeight],client:[el.clientWidth,el.clientHeight]});}for(const svg of slide.querySelectorAll('svg'))for(const t of svg.querySelectorAll('text')){const r=t.getBoundingClientRect();if(r.left<sr.left||r.right>sr.right||r.top<sr.top||r.bottom>sr.bottom)issues.push({slide:idx+1,type:'svg-label',text:t.textContent});}slide.classList.remove('active')}go(i);return issues};go(0)})();`;
 return `<!doctype html><html lang="vi"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>CEO Deck V5 Deep — ${esc(d.kind)}</title><style>${css}</style></head><body data-schema="5" data-slide-count="${totalSlides}" data-design="Premium Pharmaceutical" data-logo-sha256="${OFFICIAL_LOGO_SHA256}"><div id="deck">${body}</div><div class="controls"><button onclick="go(-1)">‹</button><span id="counter"></span><button onclick="go(1)">›</button></div><script>${js}</script></body></html>`;
